// Build critical analysis prompt with enriched context
const newsData = $input.first().json;
const sentimentData = $('Get Sentiment Data').first().json;
const calendarData = $('Get Calendar Today').first().json;
const cotData = $('Read COT Data').first().json;

const timestamp = new Date().toISOString();
const tituloNoticia = newsData.titulo || newsData.title || 'Evento crítico detectado';
const fuente = newsData.fuente || newsData.source || 'Desconocida';
const url = newsData.url || newsData.link || '';
const activosAfectados = newsData.activos_afectados || newsData.affected_assets || 'General';

const sentimentScore = sentimentData?.score || sentimentData?.sentiment_score || 'N/A';
const classification = sentimentData?.classification || sentimentData?.label || 'Neutral';

const cotInfo = cotData ? JSON.stringify(cotData, null, 2) : 'COT data no disponible';
const calendarInfo = calendarData ? JSON.stringify(calendarData, null, 2) : 'Sin eventos macro hoy';

const prompt = `ALERTA CRÍTICA — ${timestamp}

EVENTO: ${tituloNoticia}
FUENTE: ${fuente} | URL: ${url}
ACTIVOS POTENCIALMENTE AFECTADOS: ${activosAfectados}

CONTEXTO ACTUAL:
- Sentiment: ${sentimentScore} (${classification})
- COT posicionamiento: ${cotInfo}
- Eventos macro hoy: ${calendarInfo}

Analiza el impacto probable. Máximo 300 palabras. Estructura:
1. QUÉ SIGNIFICA ESTE EVENTO (contexto y precedentes)
2. IMPACTO INMEDIATO PROBABLE por activo afectado
3. SI HAY GAP DE APERTURA: probabilidad de cierre y por qué
4. QUÉ VIGILAR en las próximas 2 horas
5. ACCIÓN RECOMENDADA: qué hacer y qué evitar ahora mismo`;

return { json: { prompt, newsData, sentimentData, cotData, calendarData, timestamp } };

// Format alert with urgency indicator
const llmResponse = $input.first().json;
const promptData = $('Build Critical Analysis Prompt').first().json;

const newsData = promptData.newsData;
const analysis = llmResponse.content || llmResponse.analysis || JSON.stringify(llmResponse);

// Determine urgency based on keywords
const urgencyKeywords = ['guerra', 'crisis', 'colapso', 'default', 'emergencia', 'war', 'crisis', 'collapse'];
const textToCheck = (newsData.titulo || '') + ' ' + analysis;
const isCritical = urgencyKeywords.some(kw => textToCheck.toLowerCase().includes(kw));

const urgencyIndicator = isCritical ? '🔴 CRÍTICO' : '🟡 ATENCIÓN';
const timestamp = new Date().toISOString();

const formattedAlert = {
  id: `alert_${Date.now()}`,
  timestamp,
  urgency: urgencyIndicator,
  is_critical: isCritical,
  news: {
    title: newsData.titulo || newsData.title,
    source: newsData.fuente || newsData.source,
    url: newsData.url || newsData.link
  },
  analysis,
  context: {
    sentiment: promptData.sentimentData,
    cot: promptData.cotData,
    calendar: promptData.calendarData
  }
};

return { json: formattedAlert };
